      // Hook-level in-progress guard: prevent concurrent runs for the same session
      const HOOK_LEVEL_TIMEOUT_MS = 90_000;

      // Global dedup for multi-agent broadcast: same user within this window = skip
      const BROADCAST_DEDUP_WINDOW_MS = 3000;
      const lastHookByUser = new Map<string, number>();

      const wrapReflectionHook = (event: any) => {
        const sessionKey = typeof event?.sessionKey === "string" ? event.sessionKey : "";

        // Extract user identifier from sessionKey (format: agent:xxx:feishu:direct:ou_xxx)
        // or from context.senderId as fallback
        const sessionKeyParts = sessionKey.split(":");
        const userIdentifier = sessionKeyParts[sessionKeyParts.length - 1] ||
          (event?.context?.senderId as string) ||
          "";

        // Global dedup: if same user triggered hook recently, skip (handles broadcast to multiple agents)
        if (userIdentifier) {
          const now = Date.now();
          const lastTime = lastHookByUser.get(userIdentifier) || 0;
          if (now - lastTime < BROADCAST_DEDUP_WINDOW_MS) {
            api.logger.debug(`memory-reflection: skipping hook due to recent execution for user=${userIdentifier}; sessionKey=${sessionKey}`);
            return;
          }
          lastHookByUser.set(userIdentifier, now);
        }

        const release = reflectionInProgressBySession.get(sessionKey);
        if (release) {
          api.logger.warn(`memory-reflection: hook already in progress for sessionKey=${sessionKey || "(none)"}; skipping duplicate`);
          return;
        }
        let released = false;
        const doRelease = () => {
          if (!released) {
            released = true;
            reflectionInProgressBySession.delete(sessionKey);
          }
        };
        reflectionInProgressBySession.set(sessionKey, doRelease);
        return withTimeout(
          runMemoryReflection(event).finally(doRelease),
          HOOK_LEVEL_TIMEOUT_MS,
          "command:new reflection hook"
        ).catch((err) => {
          api.logger.warn(`memory-reflection: hook timed out after ${HOOK_LEVEL_TIMEOUT_MS}ms for sessionKey=${sessionKey}; cleared in-progress guard`);
        });
      };

      api.registerHook("command:new", wrapReflectionHook as any, {
        name: "memory-lancedb-pro.memory-reflection.command-new",
