// Hook-level in-progress guard: prevent concurrent runs for the same session
      const HOOK_LEVEL_TIMEOUT_MS = 90_000;

      // Global dedup for multi-agent broadcast in GROUP chats: same group within this window = skip
      // DM (direct) chats are independent sessions and should each run their own reflection
      const BROADCAST_DEDUP_WINDOW_MS = 3000;
      const lastHookByChat = new Map<string, number>();

      const wrapReflectionHook = (event: any) => {
        const sessionKey = typeof event?.sessionKey === "string" ? event.sessionKey : "";

        // Parse sessionKey format: agent:<agentId>:feishu:<chatType>:<chatId>
        // Examples:
        //   agent:main:feishu:direct:ou_xxx    (DM, chatType=direct, chatId=ou_xxx)
        //   agent:main:feishu:group:oc_xxx     (Group, chatType=group, chatId=oc_xxx)
        const sessionKeyParts = sessionKey.split(":");
        const chatType = sessionKeyParts[3] || ""; // "direct" or "group"
        const chatId = sessionKeyParts[4] || "";   // ou_xxx or oc_xxx

        // For GROUP chats: global dedup by chatId to handle broadcast to multiple agents
        // For DM chats: each agent session is independent, no global dedup needed
        if (chatType === "group" && chatId) {
          const now = Date.now();
          const lastTime = lastHookByChat.get(chatId) || 0;
          if (now - lastTime < BROADCAST_DEDUP_WINDOW_MS) {
            api.logger.debug(`memory-reflection: skipping hook due to recent group broadcast for chatId=${chatId}; sessionKey=${sessionKey}`);
            return;
          }
          lastHookByChat.set(chatId, now);
        }

        const release = reflectionInProgressBySession.get(sessionKey);

